import { Box, Input, Text } from "@chakra-ui/react"
import { useMutation, useQuery } from "@tanstack/react-query"
import { Button } from "components/ui/button"
import {
  DialogActionTrigger,
  DialogBody,
  DialogCloseTrigger,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogRoot,
  DialogTitle,
  DialogTrigger,
} from "components/ui/dialog"
import { Field } from "components/ui/field"
import { Switch } from "components/ui/switch"
import { enqueueSnackbar } from "notistack"
import { useState } from "react"
import { Controller, useForm } from "react-hook-form"
import { useTranslation } from "react-i18next"
import { FaPlus } from "react-icons/fa"
import { HiCheck, HiX } from "react-icons/hi"
import { queryClient } from "services"
import bankService from "services/bank"
import bankAccountService from "services/bankAccount"

const CreateBankAccount = () => {
  const [open, setOpen] = useState(false)

  const {
    control,
    formState: { errors },
    handleSubmit,
    setValue,
    watch,
  } = useForm<CreateBankAccount>()

  const enabledWebhookValue = watch("enabledWebhook")

  const { isPending, mutate } = useMutation({
    mutationFn: bankAccountService.createBankAccount,
    onError: () => {
      enqueueSnackbar(t("add_account_bank_failed"), { variant: "error" })
    },
    onSuccess: (res: any) => {
      const status = res.data.status

      if (status === "DEFAULT") {
        enqueueSnackbar(t("add_account_bank_success"), { variant: "success" })
        queryClient.invalidateQueries({ queryKey: ["bankAccountService.getAccountBankMe"] })
      } else {
        enqueueSnackbar(t("enter_otp"), { variant: "info" })
        queryClient.invalidateQueries({ queryKey: ["bankAccountService.getAccountBankMe"] })
      }
    },
  })

  const onSubmit = async (values: CreateBankAccount) => {
    values.enabledWebhook = Boolean(values.enabledWebhook)

    mutate(values)
  }
  const { data } = useQuery({
    queryFn: () => bankService.getBankAll(),
    queryKey: ["bankService.getBankAll"],
  })

  const { t } = useTranslation()

  return (
    <DialogRoot key={"center"} open={open} placement={"center"}>
      <DialogTrigger asChild>
        <Button onClick={() => setOpen(true)} variant="outline">
          <FaPlus />
          <Text className="hidden lg:block">{t("button.add_new_bank_account")}</Text>
        </Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>{t("button.add_new_bank_account")}</DialogTitle>
        </DialogHeader>
        <DialogBody>
          <Field
            errorText={errors.bankAccountName?.message}
            invalid={!!errors.bankAccountName}
            label={t("bank_account_name")}
          >
            <Controller
              control={control}
              name="bankAccountName"
              render={({ field }) => (
                <Input
                  {...field}
                  className="rounded-md border border-gray-300 pl-2.5"
                  onChange={(e) => {
                    const uppercaseValue = e.target.value.toUpperCase()
                    setValue("bankAccountName", uppercaseValue)
                    field.onChange(uppercaseValue)
                  }}
                  placeholder={t("placeholder.enter_account")}
                  value={field.value || ""}
                />
              )}
              rules={{ required: t("placeholder.enter_account") }}
            />
          </Field>

          <Field
            errorText={errors.bankAccountNo?.message}
            invalid={!!errors.bankAccountNo}
            label={t("bank_account_no")}
          >
            <Controller
              control={control}
              name="bankAccountNo"
              render={({ field }) => (
                <Input
                  {...field}
                  className="rounded-md border border-gray-300 pl-2.5"
                  placeholder={t("placeholder.enter_bank_account_number")}
                />
              )}
              rules={{ required: t("placeholder.enter_bank_account_number") }}
            />
          </Field>

          <Field errorText={errors.bankId?.message} invalid={!!errors.bankId} label={t("Bank")}>
            <Controller
              control={control}
              name="bankId"
              render={({ field }) => (
                <select
                  {...field}
                  className="w-full rounded-md border-2 border-gray-300 bg-white p-3 focus:border-blue-500 focus:outline-none"
                >
                  {data?.map((bank: Bank) => (
                    <option key={bank.id} value={bank.id}>
                      <Box className="flex items-center gap-2">
                        {bank.code} - {bank.name}
                      </Box>
                    </option>
                  ))}
                </select>
              )}
              rules={{ required: t("select_bank") }}
            />
          </Field>

          <Field errorText={errors.label?.message} invalid={!!errors.label} label={t("label")}>
            <Controller
              control={control}
              name="label"
              render={({ field }) => (
                <Input
                  {...field}
                  className="rounded-md border border-gray-300 pl-2.5"
                  placeholder={t("placeholder.enter_label")}
                />
              )}
              rules={{ required: t("placeholder.enter_label") }}
            />
          </Field>

          <Field errorText={errors.branch?.message} invalid={!!errors.branch} label={t("branch")}>
            <Controller
              control={control}
              name="branch"
              render={({ field }) => (
                <Input
                  {...field}
                  className="rounded-md border border-gray-300 pl-2.5"
                  placeholder={t("placeholder.enter_branch")}
                />
              )}
              rules={{ required: t("placeholder.enter_branch") }}
            />
          </Field>

          {enabledWebhookValue && (
            <>
              <Field errorText={errors.phoneNumber?.message} invalid={!!errors.phoneNumber} label={t("phone_number")}>
                <Controller
                  control={control}
                  name="phoneNumber"
                  render={({ field }) => (
                    <Input
                      {...field}
                      border="1px solid #ccc"
                      borderRadius="md"
                      maxLength={10}
                      placeholder={t("placeholder.enter_phone_number")}
                    />
                  )}
                  rules={{
                    pattern: {
                      message: t("placeholder.invalid_phone_number"),
                      value: /^0\d{9,10}$/,
                    },
                    required: t("placeholder.enter_phone_number"),
                  }}
                />
              </Field>

              <Field
                errorText={errors.identificationNumber?.message}
                invalid={!!errors.identificationNumber}
                label={t("identification_number")}
              >
                <Controller
                  control={control}
                  name="identificationNumber"
                  render={({ field }) => (
                    <Input
                      {...field}
                      className="rounded-md border border-gray-300 pl-2.5"
                      placeholder={t("placeholder.enter_identification_number")}
                    />
                  )}
                  rules={{ required: t("placeholder.enter_identification_number") }}
                />
              </Field>
            </>
          )}

          <Field className="flex-row-reverse justify-end" label={t("enable_webhook")}>
            <Controller
              control={control}
              name="enabledWebhook"
              render={({ field }) => {
                const selectedBankId = watch("bankId")
                const selectedBank = data?.find((bank: Bank) => bank.id === selectedBankId)
                const isSupportedHook = selectedBank?.isSupportedHook || false

                return (
                  <Switch
                    checked={field.value}
                    disabled={!isSupportedHook}
                    onCheckedChange={({ checked }) => field.onChange(Boolean(checked))}
                    size="lg"
                    thumbLabel={{
                      off: <HiX className="text-red-500" />,
                      on: <HiCheck className="text-green-500" />,
                    }}
                  />
                )
              }}
            />
          </Field>
        </DialogBody>

        <DialogCloseTrigger onClick={() => setOpen(false)} />
        <DialogFooter>
          <Button disabled={isPending} loading={isPending} onClick={handleSubmit(onSubmit)}>
            {t("confirm")}
          </Button>
          <DialogActionTrigger asChild>
            <Button className="rounded-md border-2 px-4" onClick={() => setOpen(false)}>
              {t("cancel")}
            </Button>
          </DialogActionTrigger>
        </DialogFooter>
      </DialogContent>
    </DialogRoot>
  )
}

export default CreateBankAccount

import { Box, createListCollection, Input } from "@chakra-ui/react"
import { useMutation, useQuery } from "@tanstack/react-query"
import { ADTable } from "components/ADTable"
import ReusableCollapsible from "components/Filter"
import { InputGroup } from "components/ui/input-group"
import { SelectContent, SelectItem, SelectRoot, SelectTrigger, SelectValueText } from "components/ui/select"
import { enqueueSnackbar } from "notistack"
import { useEffect, useState } from "react"
import { useTranslation } from "react-i18next"
import { LuSearch } from "react-icons/lu"
import { queryClient } from "services"
import bankAccountService from "services/bankAccount"

const BankAccount = () => {
  const [page, setPage] = useState(1)
  const [size] = useState(10)
  const [total, setTotal] = useState(0)
  const [items, setItems] = useState<BankAccount[]>([])
  const [searchValue, setSearchValue] = useState("")
  const [status, setStatus] = useState<BankAccountStatus | undefined>(undefined)

  const { data, isLoading } = useQuery({
    queryFn: () => bankAccountService.getAccountBankMe({ page, search: searchValue, size, status }),
    queryKey: ["bankAccountService.getAccountBankMe", page, searchValue, status],
  })

  const { isPending, mutate } = useMutation({
    mutationFn: (variables: { id: number }) => bankAccountService.syncVaName(variables.id),
    onSuccess: () => {
      enqueueSnackbar(t("notification.update_info_successfully"), { variant: "success" })
      queryClient.invalidateQueries({ queryKey: ["bankAccountService.getAccountBankMe"] })
    },
  })

  useEffect(() => {
    if (data?.data) {
      setTotal(data.data.total)
      setItems(data.data.items)
    }
  }, [data])

  const handleSearchChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSearchValue(e.target.value)
    setPage(1)
  }

  useEffect(() => {
    if (data?.data) {
      setItems(data.data.items)
    }
  }, [data])

  const { t } = useTranslation()

  const statusSearch = createListCollection({
    items: [
      { label: t("DEFAULT"), value: "DEFAULT" },
      { label: t("PENDING"), value: "PENDING" },
      { label: t("CONFIRMED"), value: "CONFIRMED" },
      { label: t("DELETING"), value: "DELETING" },
    ],
  })
  return (
    <Box width="full">
      <ReusableCollapsible>
        <Box className="flex flex-wrap items-center justify-between gap-5">
          <InputGroup flex="1" startElement={<LuSearch />}>
            <Input
              className="w-full rounded-md border border-gray-300 bg-white text-gray-400 focus:outline-none"
              onChange={handleSearchChange}
              placeholder={t("placeholder.bank_account_search")}
              value={searchValue}
            />
          </InputGroup>

          <SelectRoot
            className="w-full rounded-md border border-gray-300 bg-white pl-2.5 lg:w-80"
            collection={statusSearch}
            onValueChange={(e) => setStatus(e.value[0] as BankAccountStatus)}
          >
            <SelectTrigger clearable>
              <SelectValueText className="text-gray-400" placeholder={t("status")} />
            </SelectTrigger>
            <SelectContent>
              {statusSearch.items.map((e) => (
                <SelectItem item={e} key={e.value}>
                  {e.label}
                </SelectItem>
              ))}
            </SelectContent>
          </SelectRoot>
        </Box>
      </ReusableCollapsible>
      {/* <ADBankAccounts bankAccounts={items} />
       */}
      <ADTable
        configs={[
          { key: "bank.logo", label: "Bank", type: "image" },
          { key: "bankAccountNo", label: "bank_account_no", type: "string" },
          { key: "bankAccountName", label: "bank_account_name", type: "string" },
          { key: "enabledWebhook", label: "Webhook", type: "boolean" },
          { key: "branch", label: "branch", type: "string" },
          { key: "company.name", label: "company", type: "string" },
          { key: "phoneNumber", label: "phone_number", type: "string" },
          { key: "transactionFee", label: "transaction_fee", type: "currency" },
          {
            enum: {
              CONFIRMED: "green",
              DEFAULT: "blue",
              DELETING: "red",
              PENDING: "yellow",
            },
            key: "status",
            label: "status",
            type: "enum",
          },
          { key: "updatedAt", label: "updated_at", type: "datetime" },
          {
            buttons: [
              {
                isLoading: () => isPending,
                label: "button.update",
                onClick: (id) => mutate({ id }),
                visible: (item) => item?.bank?.code === "ABB",
              },
            ],
            key: "action",
            label: "action",
            type: "button",
          },
        ]}
        currentPage={page}
        hasNext={data?.data?.hasNext}
        hasPrevious={data?.data?.hasPrevious}
        items={items}
        loading={isLoading}
        onPageChange={function (page: number): void {
          setPage(page)
        }}
        size={size}
        total={total}
      />
    </Box>
  )
}

export default BankAccount

