                          </Table.Cell>
                        )
                      case "enum":
                        return (
                          <Table.Cell key={`ad_${index}`} textAlign={"center"}>
                            <Badge colorPalette={e.enum ? e.enum[item[e.key]] : ""}>
                              {t(`${keyTranslate}${value}`) ?? e.defaultValue ?? `-`}
                            </Badge>
                          </Table.Cell>
                        )
