import { Button } from "./ui/button"
import { DialogCloseTrigger, DialogContent, DialogRoot } from "./ui/dialog"
import { Loading } from "./ui/loading"
import { Switch } from "./ui/switch"

interface ADTableProps extends StackProps {
  configs: ColumnTable[]
  currentPage: number
  hasNext: boolean | undefined
  hasPrevious: boolean | undefined
  items: any[]
  loading: boolean
  onPageChange: (page: number) => void
  size: number
  total: number
}

export const ADTable = React.forwardRef<HTMLDivElement, ADTableProps>(function ADTable(
  { configs, currentPage, hasNext, hasPrevious, items, loading, onPageChange, size, total, ...props },
  ref,
) {
  const [count, setCount] = useState(total)
  const [jsonView, setJsonView] = useState("{}")
  const [contentView, setContentView] = useState("")

  useEffect(() => {
    setCount(total)
  }, [total])

  const handlePrevPage = () => {
    if (hasPrevious) {
      onPageChange(currentPage - 1)
    }
  }

  const handleNextPage = () => {
    if (hasNext) {
      onPageChange(currentPage + 1)
    }
  }
  const getNestedValue = (obj: Record<string, any>, key: string): any => {
    return key.split(".").reduce((acc, part) => acc && acc[part], obj)
  }
  const { t } = useTranslation()

  return (
    <Stack gap="3" ref={ref} width="full" {...props}>
      <Table.ScrollArea className="min-h-[50vh] rounded-md border-gray-300 shadow-lg">
        <Table.Root className="bg-white" size="md" stickyHeader>
          <Table.Header>
            <Table.Row className="h-[64px] bg-primary-main-20">
              <Table.ColumnHeader className="pl-4 font-bold" key={`stt`}>
                STT
              </Table.ColumnHeader>
              {configs.map((col, idx) => (
                <Table.ColumnHeader
                  className="font-bold"
                  key={idx}
                  textAlign={
                    col.type === "number" || col.type === "datetime" || col.type === "currency"
                      ? "end"
                      : col.type === "date" || col.type === "boolean" || col.type === "enum"
                        ? "center"
                        : "start"
                  }
                >
                  {t(`${col.label}`)}
                </Table.ColumnHeader>
              ))}
            </Table.Row>
          </Table.Header>
          <Table.Body>
            {loading ? (
              <Table.Row background={`gray.200`} height={`2xl`}>
                <Table.Cell colSpan={12} rowSpan={10} textAlign="center">
                  <Loading loading={loading} />
                </Table.Cell>
              </Table.Row>
            ) : items.length === 0 ? (
              <Table.Row>
                <Table.Cell colSpan={12} textAlign="center">
                  {t("no_records")}
                </Table.Cell>
              </Table.Row>
            ) : (
              items.map((item, index) => (
                <Table.Row className="h-[64px] transition duration-200 even:bg-gray-100 hover:bg-blue-50" key={item.id}>
                  <Table.Cell className="pl-4">{(currentPage - 1) * size + index + 1}</Table.Cell>
                  {configs.map((e, index) => {
                    const value = getNestedValue(item, e.key)
                    const keyTranslate = e.keyTranslate ? `${e.keyTranslate}.` : ``
                    switch (e.type) {
                      case "boolean":
                        return (
                          <Table.Cell key={`ad_${index}`} textAlign="center">
                            <Switch
                              checked={value}
                              colorPalette={"green"}
                              disabled={e.enableSwitch}
                              size="lg"
                              thumbLabel={{
                                off: <HiX className="text-red-500" />,
                                on: <HiCheck className="text-green-500" />,
                              }}
                            />
                          </Table.Cell>
                        )
                      case "button":
                        return (
                          <Table.Cell key={`ad_${index}`}>
                            <HStack spaceX={2}>
                              {e.buttons?.map(
                                (btn, idx) =>
                                  (typeof btn.visible === "function" ? btn.visible(item) : btn.visible !== false) && (
                                    <Button
                                      className={btn.className}
                                      key={idx}
                                      loading={typeof btn.isLoading === "function" ? btn.isLoading() : !!btn.isLoading}
                                      onClick={() => btn.onClick(item.id)}
                                    >
                                      {t(`${btn.label}`)}
                                    </Button>
                                  ),
                              )}
                            </HStack>
                          </Table.Cell>
                        )
                      case "content":
                        return (
                          <Table.Cell key={`ad_${index}`}>
                            {value ? (
                              <Box>
                                <code>{value.length > 20 ? `${value.substring(0, 20)}...` : value}</code>
                                {value.length > 20 && (
                                  <Button
                                    className="ml-2 rounded-full border-2 transition duration-300 ease-in-out hover:border-gray-300 hover:bg-gray-300"
                                    onClick={() => setContentView(value)}
                                  >
                                    <HiOutlineDotsHorizontal className="h-4 w-4" />
                                  </Button>
                                )}
                              </Box>
                            ) : (
                              (e.defaultValue ?? "-")
                            )}
                          </Table.Cell>
                        )
                      case "currency":
                        return (
                          <Table.Cell key={`ad_${index}`} textAlign="end">
                            {formatToVND(value)}
                          </Table.Cell>
                        )
                      case "datetime":
                        return (
                          <Table.Cell key={`ad_${index}`} textAlign="end">
                            {formatDate(value)}
                          </Table.Cell>
                        )
                      case "enum":
                        return (
                          <Table.Cell key={`ad_${index}`} textAlign={"center"}>
                            <Badge colorPalette={e.enum ? e.enum[item[e.key]] : ""}>
                              {t(`${keyTranslate}${value}`) ?? e.defaultValue ?? `-`}
                            </Badge>
                          </Table.Cell>
                        )
                      case "image":
                        return (
                          <Table.Cell key={`ad_${index}`}>
                            <Image className="h-[40px] object-contain" src={value}></Image>
                          </Table.Cell>
                        )
                      case "json":
                        return (
                          <Table.Cell key={`ad_${index}`}>
                            {value ? (
                              <Box>
                                <code>{value.length > 20 ? `${value.substring(0, 20)}...` : value}</code>
                                <Button
                                  className="ml-2 rounded-full border-2 transition duration-300 ease-in-out hover:border-gray-300 hover:bg-gray-300"
                                  onClick={() => setJsonView(value)}
                                >
                                  <HiOutlineDotsHorizontal className="h-4 w-4" />
                                </Button>
                              </Box>
                            ) : (
                              (e.defaultValue ?? "-")
                            )}
                          </Table.Cell>
                        )

                      case "number":
                        return (
                          <Table.Cell key={`ad_${index}`} textAlign="end">
                            {value}
                          </Table.Cell>
                        )
                      case "to":
                        return (
                          <Table.Cell key={`ad_${index}`}>
                            <Link className="text-primary-main hover:underline" to={`${e.path}/${item.id}`}>
                              {value}
                            </Link>
                          </Table.Cell>
                        )
                      default:
                        return <Table.Cell key={`ad_${index}`}>{value ?? e.defaultValue ?? `-`} </Table.Cell>
                    }
                  })}
                </Table.Row>
              ))
            )}
          </Table.Body>
        </Table.Root>
      </Table.ScrollArea>
      <PaginationRoot count={count} onPageChange={(e) => onPageChange(e.page)} pageSize={size}>
        <HStack justify="center" wrap="wrap">
          <PaginationPrevTrigger disabled={!hasPrevious} onClick={handlePrevPage} />
          <PaginationItems />
          <PaginationNextTrigger disabled={!hasNext} onClick={handleNextPage} />
        </HStack>
      </PaginationRoot>

      {/* modal json view */}
      <DialogRoot onOpenChange={(open) => !open && setJsonView("{}")} open={jsonView !== "{}"} placement={"center"}>
        <DialogContent className="w-[600px] max-w-full transform rounded-md bg-white p-6 shadow-xl transition-all duration-300 ease-in-out">
          <Heading className="mb-4 text-center text-2xl font-semibold text-gray-800">{t("detail")}</Heading>
          <pre className="max-h-[400px] min-h-[30vh] overflow-auto whitespace-pre-wrap rounded-md bg-gray-50 p-6 text-sm text-gray-700 shadow-inner">
            <code>{JSON.stringify(JSON.parse(jsonView), null, 2)}</code>
          </pre>
          <DialogCloseTrigger onClick={() => setJsonView("{}")} />
        </DialogContent>
      </DialogRoot>

      {/* modal json view */}
      <DialogRoot onOpenChange={(open) => !open && setContentView("")} open={contentView !== ""} placement={"center"}>
        <DialogContent className="w-[600px] max-w-full transform rounded-md bg-white p-6 shadow-xl transition-all duration-300 ease-in-out">
          <Heading className="mb-4 text-center text-2xl font-semibold text-gray-800">{t("detail")}</Heading>
          <pre className="max-h-[400px] min-h-[30vh] overflow-auto whitespace-pre-wrap rounded-md bg-gray-50 p-6 text-sm text-gray-700 shadow-inner">
            <code>{contentView}</code>
          </pre>
          <DialogCloseTrigger onClick={() => setContentView("")} />
        </DialogContent>
      </DialogRoot>
    </Stack>
  )
})

ADTable.displayName = "ADTable"

