import axios, { AxiosError, AxiosRequestConfig, InternalAxiosRequestConfig } from "axios"
import { API_URL } from "env"
import i18next from "i18n"
import { jwtDecode } from "jwt-decode"
import { enqueueSnackbar } from "notistack"
import authService from "services/auth"
import { useUserStore } from "store/userStore"

interface AxiosRequestConfigWithRetry extends AxiosRequestConfig {
  _retry?: boolean
}

const beforeRequest = (config: InternalAxiosRequestConfig) => {
  const { user } = useUserStore.getState()
  if (user?.accessToken) {
    Object.assign(config.headers, {
      Authorization: `Bearer ${user.accessToken}`,
    })
  }
  if (config.data instanceof FormData) {
    Object.assign(config.headers, {
      "Content-Type": "multipart/form-data",
    })
  }
  return config
}

let isRefreshing = false
const tryRefreshToken = async () => {
  const { clearUser, setUser, user } = useUserStore.getState()
  if (isRefreshing) {
    await new Promise((resolve) => setTimeout(() => resolve(null), 100))
    await tryRefreshToken()
  } else {
    if (!user?.accessToken || !user?.refreshToken) {
      clearUser()
    }
    if (user?.accessToken) {
      const payload = jwtDecode(user.accessToken)
      if (payload.exp! * 1e3 > new Date().getTime()) return
      isRefreshing = true
      await authService
        .refreshToken({ refreshToken: user.refreshToken })
        .then((refreshInfo) => {
          setUser(refreshInfo)
        })
        .catch(() => {
          enqueueSnackbar(i18next.t("session_expired"), { key: "SESSION_EXPIRED", variant: "info" })
          clearUser()
        })
        .finally(() => {
          isRefreshing = false
        })
    } else {
      clearUser()
    }
  }
}

const onError = async (error: AxiosError<ErrorResponse, string>) => {
  const { response } = error
  const { clearUser } = useUserStore.getState()

  if (response) {
    const { data, status } = response
    const isAuth = error.config?.url?.startsWith("/auth")
    if (!isAuth && status === 401) {
      const originalRequest = error.config as AxiosRequestConfigWithRetry
      if (!originalRequest._retry) {
        originalRequest._retry = true
        await tryRefreshToken()
        return client(originalRequest)
      } else {
        enqueueSnackbar(i18next.t("session_expired"), { key: "SESSION_EXPIRED", variant: "info" })
        clearUser()
      }
    } else {
      enqueueSnackbar(
        status === 401 ? i18next.t("login_failed") : (i18next.t(data.message) ?? i18next.t("unknown_error")),
        {
          variant: "error",
        },
      )
    }
  } else {
    enqueueSnackbar(i18next.t("error_connecting_to_the_system"), { variant: "error" })
  }
  return Promise.reject(error)
}

const client = axios.create({ baseURL: `${API_URL}/api` })
client.interceptors.request.use(beforeRequest)
client.interceptors.response.use(({ data }) => data, onError)

export { client }

