import { queryClient } from "services"
import bankService from "services/bank"
import bankAccountService from "services/bankAccount"

const CreateBankAccount = () => {
  const [open, setOpen] = useState(false)

  const {
    control,
    formState: { errors },
    handleSubmit,
    setValue,
    watch,
  } = useForm<CreateBankAccount>()

  const enabledWebhookValue = watch("enabledWebhook")

  const { isPending, mutate } = useMutation({
    mutationFn: bankAccountService.createBankAccount,
    onError: () => {
      enqueueSnackbar(t("add_account_bank_failed"), { variant: "error" })
    },
    onSuccess: (res: any) => {
      const status = res.data.status

      if (status === "DEFAULT") {
        enqueueSnackbar(t("add_account_bank_success"), { variant: "success" })
        queryClient.invalidateQueries({ queryKey: ["bankAccountService.getAccountBankMe"] })
      } else {
        enqueueSnackbar(t("enter_otp"), { variant: "info" })
        queryClient.invalidateQueries({ queryKey: ["bankAccountService.getAccountBankMe"] })
      }
    },
  })

  const onSubmit = async (values: CreateBankAccount) => {
    values.enabledWebhook = Boolean(values.enabledWebhook)

    mutate(values)
  }
  const { data } = useQuery({
    queryFn: () => bankService.getBankAll(),
    queryKey: ["bankService.getBankAll"],
  })

  const { t } = useTranslation()

  return (
    <DialogRoot key={"center"} open={open} placement={"center"}>
