        <DialogHeader>
          <DialogTitle>{t("button.add_new_bank_account")}</DialogTitle>
        </DialogHeader>
        <DialogBody>
          <Field errorText={errors.bankId?.message} invalid={!!errors.bankId} label={t("Bank")}>
            <Controller
              control={control}
              name="bankId"
              render={({ field }) => (
                <select
                  {...field}
                  className="w-full rounded-md border-2 border-gray-300 bg-white p-3 focus:border-blue-500 focus:outline-none"
                >
                  {data?.map((bank: Bank) => (
                    <option key={bank.id} value={bank.id}>
                      {bank.code} - {bank.name}
                    </option>
                  ))}
                </select>
              )}
              rules={{ required: t("select_bank") }}
            />
          </Field>

          <Field
            errorText={errors.bankAccountNo?.message}
            invalid={!!errors.bankAccountNo}
            label={t("bank_account_no")}
          >
            <Controller
              control={control}
              name="bankAccountNo"
              render={({ field }) => (
                <Input
                  {...field}
                  className="rounded-md border border-gray-300 pl-2.5"
                  placeholder={t("placeholder.enter_bank_account_number")}
