import { Box, createListCollection, Input } from "@chakra-ui/react"
import { useMutation, useQuery } from "@tanstack/react-query"
import { ADTable } from "components/ADTable"
import ReusableCollapsible from "components/Filter"
import { InputGroup } from "components/ui/input-group"
import { SelectContent, SelectItem, SelectRoot, SelectTrigger, SelectValueText } from "components/ui/select"
import { enqueueSnackbar } from "notistack"
import { useEffect, useState } from "react"
import { useTranslation } from "react-i18next"
import { LuSearch } from "react-icons/lu"
import { queryClient } from "services"
import bankAccountService from "services/bankAccount"

import CreateBankAccount from "./CreateBankAccount"

const BankAccount = () => {
  const [page, setPage] = useState(1)
  const [size] = useState(10)
  const [total, setTotal] = useState(0)
  const [items, setItems] = useState<BankAccount[]>([])
  const [searchValue, setSearchValue] = useState("")
  const [status, setStatus] = useState<BankAccountStatus | undefined>(undefined)

  const { data, isLoading } = useQuery({
    queryFn: () => bankAccountService.getAccountBankMe({ page, search: searchValue, size, status }),
    queryKey: ["bankAccountService.getAccountBankMe", page, searchValue, status],
  })

  const { isPending, mutate } = useMutation({
    mutationFn: (variables: { id: number }) => bankAccountService.syncVaName(variables.id),
    onSuccess: () => {
      enqueueSnackbar(t("notification.update_info_successfully"), { variant: "success" })
      queryClient.invalidateQueries({ queryKey: ["bankAccountService.getAccountBankMe"] })
    },
  })

  useEffect(() => {
    if (data?.data) {
      setTotal(data.data.total)
      setItems(data.data.items)
    }
  }, [data])

  const handleSearchChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSearchValue(e.target.value)
    setPage(1)
  }

  useEffect(() => {
    if (data?.data) {
      setItems(data.data.items)
    }
  }, [data])

  const { t } = useTranslation()

  const statusSearch = createListCollection({
    items: [
      { label: t("DEFAULT"), value: "DEFAULT" },
      { label: t("PENDING"), value: "PENDING" },
      { label: t("CONFIRMED"), value: "CONFIRMED" },
      { label: t("DELETING"), value: "DELETING" },
    ],
  })
  return (
    <Box width="full">
      <ReusableCollapsible>
        <Box className="flex flex-wrap items-center justify-between gap-5">
          <InputGroup flex="1" startElement={<LuSearch />}>
            <Input
              className="w-full rounded-md border border-gray-300 bg-white text-gray-400 focus:outline-none"
              onChange={handleSearchChange}
              placeholder={t("placeholder.bank_account_search")}
              value={searchValue}
            />
          </InputGroup>

          <SelectRoot
            className="w-full rounded-md border border-gray-300 bg-white pl-2.5 lg:w-80"
            collection={statusSearch}
            onValueChange={(e) => setStatus(e.value[0] as BankAccountStatus)}
          >
            <SelectTrigger clearable>
              <SelectValueText className="text-gray-400" placeholder={t("status")} />
            </SelectTrigger>
            <SelectContent>
              {statusSearch.items.map((e) => (
                <SelectItem item={e} key={e.value}>
                  {e.label}
                </SelectItem>
              ))}
            </SelectContent>
          </SelectRoot>

          <CreateBankAccount />
        </Box>
      </ReusableCollapsible>
      {/* <ADBankAccounts bankAccounts={items} />
       */}
      <ADTable
        configs={[
          { key: "bank.logo", label: "Bank", type: "image" },
          { key: "bankAccountNo", label: "bank_account_no", type: "string" },
          { key: "bankAccountName", label: "bank_account_name", type: "string" },
          { key: "enabledWebhook", label: "Webhook", type: "boolean" },
          { key: "branch", label: "branch", type: "string" },
          { key: "company.name", label: "company", type: "string" },
          { key: "phoneNumber", label: "phone_number", type: "string" },
          { key: "transactionFee", label: "transaction_fee", type: "currency" },
          {
            enum: {
              CONFIRMED: "green",
              DEFAULT: "blue",
              DELETING: "red",
              PENDING: "yellow",
            },
            key: "status",
            label: "status",
            type: "enum",
          },
          { key: "updatedAt", label: "updated_at", type: "datetime" },
          {
            buttons: [
              {
                isLoading: () => isPending,
                label: "button.update",
                onClick: (id) => mutate({ id }),
                visible: (item) => item?.bank?.code === "ABB",
              },
            ],
            key: "action",
            label: "action",
            type: "button",
          },
        ]}
        currentPage={page}
        hasNext={data?.data?.hasNext}
        hasPrevious={data?.data?.hasPrevious}
        items={items}
        loading={isLoading}
        onPageChange={function (page: number): void {
          setPage(page)
        }}
        size={size}
        total={total}
      />
    </Box>
  )
}

export default BankAccount

