import {
  Body,
  Controller,
  Delete,
  ForbiddenException,
  Get,
  Param,
  Patch,
  Post,
  Query,
} from '@nestjs/common';
import { ApiResponse, ApiTags } from '@nestjs/swagger';

import { BankAccountService } from '@bank-account/bank-account.service';
import { BankAccountDto, BankAccountNameDto, BankAccountQueryParams, CreateBankAccountDto, UpdateBankAccountDto, VerifyBankAccountDto } from '@bank-account/dto';

import { Role, User } from '@modules/user/entities';
import { CompanyService } from '@modules/company';

import { BaseResult } from '@utils/base.result';
import { BaseResultPagination } from '@utils/base.result.pagination';
import { Admin, Auth, Created, Login, UserLogin } from '@utils/decorators';
import { PaginationDto } from '@utils/pagination.dto';

@ApiTags('Api Tài khoản ngân hàng')
@Controller('bank-account')
@Login()
export class BankAccountController {
  constructor(
    private readonly bankAccountService: BankAccountService,
    private readonly companyService: CompanyService,
  ) { }

  @Post()
  @Auth(Role.User, Role.Admin)
  @Created()
  async create(@UserLogin() user: User, @Body() createBankAccountDto: CreateBankAccountDto) {
    let company = user.company;
    if (createBankAccountDto.companyId) {
      if (user.role !== Role.Admin) throw new ForbiddenException();
      company = await this.companyService.findOneExist(createBankAccountDto.companyId);
    }
    const item = await this.bankAccountService.create(company, createBankAccountDto, user);
    return new BaseResult<BankAccountDto>(new BankAccountDto(item));
  }

  @Get()
  @Admin()
  @ApiResponse({ type: BaseResultPagination<BankAccountDto> })
  async find(@Query() query: BankAccountQueryParams) {
    const [items, count] = await this.bankAccountService.find(query);
    const rs = new BaseResultPagination<BankAccountDto>();
    rs.data = new PaginationDto<BankAccountDto>(items.map(e => new BankAccountDto(e)), count, query.page, query.size);
    return rs;
  }

  @Get('me')
  @ApiResponse({ type: BaseResultPagination<BankAccountDto> })
  async findMe(@UserLogin() user: User, @Query() query: BankAccountQueryParams) {
    query.company = { id: user.company?.id };
    const [items, count] = await this.bankAccountService.find(query);
    const rs = new BaseResultPagination<BankAccountDto>();
    rs.data = new PaginationDto<BankAccountDto>(items.map(e => new BankAccountDto(e)), count, query.size, query.page);
    return rs;
  }

  @Get('bank-holder')
  @ApiResponse({ type: String })
  getBankHolderName(@Query() query: BankAccountNameDto) {
    return this.bankAccountService.getBankHolderName(query);
  }

  @Get('sync-sepay')
  @Admin()
  @ApiResponse({ type: BaseResult })
  syncBankAccountFromSepay(@Query() query: {
    companyId: string,
    bankId: string
  }) {
    return this.bankAccountService.syncBankAccountFromSepay(query.companyId, query.bankId);
  }

  @Get(':id')
  @ApiResponse({ type: BankAccountDto })
  async findOne(@UserLogin() user: User, @Param('id') id: number) {
    const item = await this.bankAccountService.findOneExist(+id);
    if (item.company?.id != user.company?.id && user.role != Role.Admin) throw new ForbiddenException();
    return new BankAccountDto(item);
  }

  @Patch(':id')
  @ApiResponse({ type: BaseResult })
  async update(
    @UserLogin() user: User,
    @Param('id') id: number,
    @Body() updateBankAccountDto: UpdateBankAccountDto,
  ) {
    await this.bankAccountService.update(+id, updateBankAccountDto, user.company, user);
    return new BaseResult();
  }

  @Delete(':id')
  @ApiResponse({ type: BaseResult })
  async remove(
    @UserLogin() user: User,
    @Param('id') id: number) {
    await this.bankAccountService.remove(+id, user.company, user);
    return new BaseResult();
  }

  @Post(':id/resend-otp')
  @ApiResponse({ type: BaseResult })
  async resendOTP(
    @UserLogin() user: User,
    @Param('id') id: number) {
    await this.bankAccountService.resendOtp(user.company, +id);
    return new BaseResult();
  }

  @Post(':id/verify-otp')
  @ApiResponse({ type: BaseResult })
  async verifyOTP(
    @UserLogin() user: User,
    @Param('id') id: number,
    @Body() body: VerifyBankAccountDto,
  ) {
    await this.bankAccountService.verifyOtp(user.company, +id, body.otp);
    return new BaseResult();
  }

  @Post(':id/sync-va-name')
  @ApiResponse({ type: BaseResult })
  async syncVAName(
    @Param('id') id: number) {
    await this.bankAccountService.syncVaName(+id);
    return new BaseResult();
  }
}

import { Input, Text } from "@chakra-ui/react"
import { useMutation } from "@tanstack/react-query"
import { Button } from "components/ui/button"
import {
  DialogActionTrigger,
  DialogBody,
  DialogCloseTrigger,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogRoot,
  DialogTitle,
  DialogTrigger,
} from "components/ui/dialog"
import { Field } from "components/ui/field"
import { enqueueSnackbar } from "notistack"
import { useState } from "react"
import { Controller, useForm } from "react-hook-form"
import { useTranslation } from "react-i18next"
import { FaPlus } from "react-icons/fa"
import { queryClient } from "services"
import bankAccountService from "services/bankAccount"

const VerifyOtp = (id: number) => {
  const [open, setOpen] = useState(false)

  const {
    control,
    formState: { errors },
    handleSubmit,
  } = useForm<VerifyOtp>()

  const { isPending, mutate } = useMutation({
    mutationFn: (data: VerifyOtp) => bankAccountService.verifyOtp(id, data),
    onError: () => {
      enqueueSnackbar("Xác nhận OTP thất bại!", { variant: "error" })
    },
    onSuccess: () => {
      enqueueSnackbar("Xác nhận OTP thành công!", { variant: "success" })
      queryClient.invalidateQueries({ queryKey: ["bankAccountService.getAccountBankMe"] })
      setOpen(false)
    },
  })

  const onSubmit = (values: VerifyOtp) => {
    mutate(values)
  }
  const { t } = useTranslation()

  const useResend = useMutation({
    mutationFn: () => bankAccountService.resendOtp(id),
    onError: () => {
      enqueueSnackbar(t("send_otp_failed"), { variant: "error" })
    },
    onSuccess: () => {
      enqueueSnackbar(t("send_otp_success"), { variant: "success" })
      queryClient.invalidateQueries({ queryKey: ["bankAccountService.getAccountBankMe"] })
      setOpen(false)
    },
  })

  const resend = () => {
    useResend.mutate()
  }

  return (
    <DialogRoot key={"center"} open={open} placement={"center"}>
      <DialogTrigger asChild>
        <Button onClick={() => setOpen(true)} variant="outline">
          <FaPlus />
          <Text className="hidden lg:block">{t("bank_account_verification")}</Text>
        </Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>{t("bank_account_verification")}</DialogTitle>
        </DialogHeader>
        <DialogBody>
          <Field errorText={errors.otp?.message} invalid={!!errors.otp} label={t("otp_code")}>
            <Controller
              control={control}
              name="otp"
              render={({ field }) => (
                <Input
                  {...field}
                  className="rounded-md border border-gray-300 pl-2.5"
                  onChange={(e) => {
                    const uppercaseValue = e.target.value.toUpperCase()
                    field.onChange(uppercaseValue)
                  }}
                  placeholder={t("placeholder.enter_otp_code")}
                  value={field.value || ""}
                />
              )}
              rules={{ required: t("placeholder.enter_otp_code") }}
            />
          </Field>
        </DialogBody>

        <DialogCloseTrigger onClick={() => setOpen(false)} />
        <DialogFooter>
          <Button disabled={isPending} loading={isPending} onClick={resend}>
            {t("resend_otp")}
          </Button>
          <Button disabled={isPending} loading={isPending} onClick={handleSubmit(onSubmit)}>
            {t("confirm")}
          </Button>
          <DialogActionTrigger asChild>
            <Button className="rounded-md border-2 px-4" onClick={() => setOpen(false)}>
              {t("cancel")}
            </Button>
          </DialogActionTrigger>
        </DialogFooter>
      </DialogContent>
    </DialogRoot>
  )
}

export default VerifyOtp

