const BANK_HOLDER_LOOKUP_DEBOUNCE_MS = 3000

const normalizeText = (value?: string) => value?.trim() ?? ""

const toUppercase = (value: string) => value.toUpperCase()

type UseBankHolderLookupParams = {
  bankAccountNo?: string
  canLookup: boolean
  externalBankId?: number
  open: boolean
  setValue: UseFormSetValue<CreateBankAccount>
}

const useBankHolderLookup = ({
  bankAccountNo,
  canLookup,
  externalBankId,
  open,
  setValue,
}: UseBankHolderLookupParams) => {
  const [isResolvingBankHolder, setIsResolvingBankHolder] = useState(false)
  const [lookupBankAccountNo, setLookupBankAccountNo] = useState("")
  const lastResolvedKeyRef = useRef("")
  const pendingKeyRef = useRef("")

  const commitLookup = (value?: string) => {
    const normalizedValue = normalizeText(value)
    setLookupBankAccountNo((currentValue) => (currentValue === normalizedValue ? currentValue : normalizedValue))
  }

  useEffect(() => {
    if (open) return

    setLookupBankAccountNo("")
    setIsResolvingBankHolder(false)
    lastResolvedKeyRef.current = ""
    pendingKeyRef.current = ""
  }, [open])

  useEffect(() => {
    if (!open) return

    const timeoutId = window.setTimeout(() => {
      commitLookup(bankAccountNo)
    }, BANK_HOLDER_LOOKUP_DEBOUNCE_MS)

    return () => clearTimeout(timeoutId)
  }, [bankAccountNo, open])

  useEffect(() => {
    if (!open || !canLookup || externalBankId == null || !lookupBankAccountNo) {
      setIsResolvingBankHolder(false)
      return
    }

    const requestKey = `${externalBankId}:${lookupBankAccountNo}`
    if (pendingKeyRef.current === requestKey || lastResolvedKeyRef.current === requestKey) {
      return
    }

    let isActive = true
    pendingKeyRef.current = requestKey
    setIsResolvingBankHolder(true)

    ;(async () => {
      try {
        const bankHolderName = await bankAccountService.getBankHolder({
          bankAccountNo: lookupBankAccountNo,
          externalBankId,
        })

        if (!isActive) return

        const normalizedBankHolderName = normalizeText(bankHolderName)
        if (normalizedBankHolderName) {
          setValue("bankAccountName", toUppercase(normalizedBankHolderName), { shouldValidate: true })
        }

        lastResolvedKeyRef.current = requestKey
      } finally {
        if (pendingKeyRef.current === requestKey) {
          pendingKeyRef.current = ""
        }

        if (isActive) {
          setIsResolvingBankHolder(false)
        }
      }
    })()

    return () => {
      isActive = false
    }
  }, [canLookup, externalBankId, lookupBankAccountNo, open, setValue])

  return {
    commitLookup,
    isResolvingBankHolder,
  }
}

