} from "components/ui/dialog"
import { Field } from "components/ui/field"
import { Switch } from "components/ui/switch"
import { enqueueSnackbar } from "notistack"
import { useEffect, useRef, useState } from "react"
import { Controller, useForm, type UseFormSetValue, useWatch } from "react-hook-form"
import { useTranslation } from "react-i18next"
import { FaPlus } from "react-icons/fa"
import { HiCheck, HiX } from "react-icons/hi"
import { queryClient } from "services"
import bankService from "services/bank"
import bankAccountService from "services/bankAccount"

import VerifyOtpDialog from "./VerifyOtp"

const BANK_HOLDER_LOOKUP_DEBOUNCE_MS = 3000

const normalizeText = (value?: string) => value?.trim() ?? ""

const toUppercase = (value: string) => value.toUpperCase()

type UseBankHolderLookupParams = {
  bankAccountNo?: string
  canLookup: boolean
  externalBankId?: number
  open: boolean
  setValue: UseFormSetValue<CreateBankAccount>
}

const useBankHolderLookup = ({
  bankAccountNo,
  canLookup,
  externalBankId,
  open,
  setValue,
}: UseBankHolderLookupParams) => {
  const [isResolvingBankHolder, setIsResolvingBankHolder] = useState(false)
  const [lookupBankAccountNo, setLookupBankAccountNo] = useState("")
  const lastResolvedKeyRef = useRef("")
  const pendingKeyRef = useRef("")

  const commitLookup = (value?: string) => {
    const normalizedValue = normalizeText(value)
    setLookupBankAccountNo((currentValue) => (currentValue === normalizedValue ? currentValue : normalizedValue))
  }

  useEffect(() => {
    if (open) return

    setLookupBankAccountNo("")
    setIsResolvingBankHolder(false)
    lastResolvedKeyRef.current = ""
    pendingKeyRef.current = ""
  }, [open])

  useEffect(() => {
    if (!open) return

    const timeoutId = window.setTimeout(() => {
      commitLookup(bankAccountNo)
    }, BANK_HOLDER_LOOKUP_DEBOUNCE_MS)

    return () => clearTimeout(timeoutId)
  }, [bankAccountNo, open])

  useEffect(() => {
    if (!open || !canLookup || externalBankId == null || !lookupBankAccountNo) {
      setIsResolvingBankHolder(false)
      return
    }

    const requestKey = `${externalBankId}:${lookupBankAccountNo}`
    if (pendingKeyRef.current === requestKey || lastResolvedKeyRef.current === requestKey) {
      return
    }

    let isActive = true
    pendingKeyRef.current = requestKey
    setIsResolvingBankHolder(true)
    ;(async () => {
      try {
        const bankHolderName = await bankAccountService.getBankHolder({
          bankAccountNo: lookupBankAccountNo,
          externalBankId,
        })

        if (!isActive) return

        const normalizedBankHolderName = normalizeText(bankHolderName)
        if (normalizedBankHolderName) {
          setValue("bankAccountName", toUppercase(normalizedBankHolderName), { shouldValidate: true })
        }

        lastResolvedKeyRef.current = requestKey
      } finally {
        if (pendingKeyRef.current === requestKey) {
          pendingKeyRef.current = ""
        }

        if (isActive) {
          setIsResolvingBankHolder(false)
        }
      }
    })()

    return () => {
      isActive = false
    }
  }, [canLookup, externalBankId, lookupBankAccountNo, open, setValue])

  return {
    commitLookup,
    isResolvingBankHolder,
  }
}

const CreateBankAccount = () => {
  const [open, setOpen] = useState(false)
  const [verifyOtpBankAccountId, setVerifyOtpBankAccountId] = useState<null | number>(null)

  const {
    control,
    formState: { errors },
    handleSubmit,
    reset,
    setValue,
  } = useForm<CreateBankAccount>()

  const { t } = useTranslation()
  const enabledWebhookValue = useWatch({ control, name: "enabledWebhook" })
  const selectedBankId = useWatch({ control, name: "bankId" })
  const bankAccountNo = useWatch({ control, name: "bankAccountNo" })

  const { data: banks = [] } = useQuery({
    enabled: open,
    queryFn: () => bankService.getBankAll(),
    queryKey: ["bankService.getBankAll"],
  })

  const selectedBank = banks.find((bank: Bank) => bank.id === Number(selectedBankId))
  const canEnableWebhook = Boolean(selectedBank?.isSupportedHook)
  const canLookupBankHolder = canEnableWebhook && selectedBank?.externalId != null
  const { commitLookup, isResolvingBankHolder } = useBankHolderLookup({
    bankAccountNo,
    canLookup: canLookupBankHolder,
    externalBankId: selectedBank?.externalId,
    open,
    setValue,
  })

  const { isPending, mutate } = useMutation({
    mutationFn: bankAccountService.createBankAccount,
    onError: () => {
      enqueueSnackbar(t("add_account_bank_failed"), { variant: "error" })
    },
    onSuccess: (res: any) => {
      const createdBankAccount = res.data as BankAccount
      const status = createdBankAccount.status

      queryClient.invalidateQueries({ queryKey: ["bankAccountService.getAccountBankMe"] })
      queryClient.invalidateQueries({ queryKey: ["bankAccountService.getAccountBank"] })
      reset()
      setOpen(false)

      if (status === BankAccountStatus.PENDING) {
        enqueueSnackbar(t("enter_otp"), { variant: "info" })
        setVerifyOtpBankAccountId(createdBankAccount.id)
        return
      }

      enqueueSnackbar(t("add_account_bank_success"), { variant: "success" })
    },
  })

  const handleClose = () => {
    reset()
    setOpen(false)
  }

  const onSubmit = (values: CreateBankAccount) => {
    mutate({
      ...values,
      enabledWebhook: Boolean(values.enabledWebhook),
    })
  }

  useEffect(() => {
    if (!canEnableWebhook && enabledWebhookValue) {
      setValue("enabledWebhook", false)
    }
  }, [canEnableWebhook, enabledWebhookValue, setValue])

  return (
    <>
      <DialogRoot key={"center"} open={open} placement={"center"}>
        <DialogTrigger asChild>
          <Button onClick={() => setOpen(true)} variant="outline">
            <FaPlus />
            <Text className="hidden lg:block">{t("button.add_new_bank_account")}</Text>
          </Button>
        </DialogTrigger>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("button.add_new_bank_account")}</DialogTitle>
          </DialogHeader>
          <DialogBody>
            <Field errorText={errors.bankId?.message} invalid={!!errors.bankId} label={t("Bank")}>
              <Controller
                control={control}
                name="bankId"
                render={({ field }) => (
                  <select
                    className="w-full rounded-md border-2 border-gray-300 bg-white p-3 focus:border-blue-500 focus:outline-none"
                    name={field.name}
                    onBlur={field.onBlur}
                    onChange={(e) => field.onChange(e.target.value ? Number(e.target.value) : undefined)}
                    ref={field.ref}
                    value={field.value ?? ""}
                  >
                    <option value="">{t("select_bank")}</option>
                    {banks.map((bank: Bank) => (
                      <option key={bank.id} value={bank.id}>
                        {bank.code} - {bank.name}
                      </option>
                    ))}
                  </select>
                )}
                rules={{ required: t("select_bank") }}
              />
            </Field>

            <Field
              errorText={errors.bankAccountNo?.message}
              invalid={!!errors.bankAccountNo}
              label={t("bank_account_no")}
            >
              <Controller
                control={control}
                name="bankAccountNo"
                render={({ field }) => (
                  <Input
                    {...field}
                    className="rounded-md border border-gray-300 pl-2.5"
                    onBlur={(e) => {
                      field.onBlur()
                      commitLookup(e.target.value)
                    }}

